var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"범은 기만의 짐승이다.","JPN":"虎は欺瞞のケモノだ。","ENG":"The Tiger is a deceiving Beast.","TWN":"老虎是欺瞞的野獸。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"자신의 약점이 무엇인지 알고 있다면, 놈은 오히려 함정을 파고 빈틈을 드러내겠지.","JPN":"己の弱点が分かるなら、やつはそこに罠を仕掛けて隙を見せるだろう。","ENG":"If we know its weakness, it'll lay a trap and expose a false opening.","TWN":"如果知道自己的弱點在哪，牠反而會設下陷阱，露出破綻。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"내가 놈의 앞발 쳐낼 테니, 넌 목덜미를 노리거라.","JPN":"俺がやつの前足を牽制する。お前は首元を狙え。","ENG":"I'll handle its forelegs. Go for the nape.","TWN":"你擋下牠的前爪，我來瞄準脖子。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"허면 그 함정이란 것은…?","JPN":"その罠とは……？","ENG":"Then the trap is…?","TWN":"那麼那個陷阱是…？"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"제 아무리 무서운 범이라 한들, 결국 머리는 하나에 네 발 달린 짐승이다.","JPN":"いくらあの恐ろしい虎でも、所詮は頭1つに足が4つ付いたケモノに過ぎない。","ENG":"No matter how fearsome the Tiger, it's still a Beast with one head and four limbs, basically an animal.","TWN":"再怎麼可怕的老虎，終究只有一個頭和四條腿。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"등에서 팔이라도 돋지 않는 한, 놈이 숨겨둔 수가 무엇인진 뻔하지.","JPN":"背中から腕でも生えない限り、やつが隠している手は見え透いている。","ENG":"Unless it's got arms sprouting from its back, its options are obvious.","TWN":"只要牠背上不會長出手臂，牠藏起來的招數就很明顯。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"지금이다!","JPN":"今だ！","ENG":"Now!","TWN":"就是現在！"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"합!","JPN":"はっ！","ENG":"Hup!","TWN":"喝！"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"역시, 노리고 있던 건 그곳인가.","JPN":"やはり狙いはそこか。","ENG":"As expected, that's the spot you were aiming for all along.","TWN":"果然，你瞄準的就是那裡。"},"stage":{"bg":"MS_1501_2","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"분명 범의 목을 노리고 달려들었으면서, 왜 뒤를 막은 거지?","JPN":"確かに虎の首を狙って飛び掛かったのに、なぜ背中を防御した？","ENG":"You rushed straight for the Tiger's neck. So why did you block the rear?","TWN":"你明明是衝著老虎的脖子來的，為什麼要擋住後面？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대의 살기가 너무 강하여, 눈치 챌 수밖에 없었네.","JPN":"そなたの殺気が強すぎて、気づかずにはいられなかった。","ENG":"The stench of your bloodlust was impossible to ignore. I couldn't help but notice.","TWN":"你的殺氣太強，我不得不察覺。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…처음부터 함정인 줄 알고 있었구나.","JPN":"……最初から罠だと分かっていたのね。","ENG":"…You knew it was a trap from the start, didn't you?","TWN":"…你從一開始就知道這是陷阱。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"큭…!","JPN":"くっ……！","ENG":"Kgh…!","TWN":"咳…！"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신에게 승산은 없어. 명달에게 범을 맡기고 들어온 건 큰 실수야.","JPN":"あなたに勝ち目はないわ。アカタツに虎を任せて入って来るなんて。","ENG":"You don't stand a chance. Leaving the Tiger to Myeongdal was a grave mistake.","TWN":"你沒有勝算。把老虎交給明達，然後衝進來是個大錯。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"통계학적으로 보았을 때, 승산이 아주 없는 건 아닐세.","JPN":"統計学的に勝ち目はゼロではない。","ENG":"Statistically speaking, the odds aren't zero.","TWN":"從統計學來看，並非完全沒有勝算。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나도 한 번은 그댈 이겼잖은가.","JPN":"1度は某が勝ったではないか。","ENG":"I did beat you once, didn't I?","TWN":"我不也贏過你一次嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 한 번은 운이 따라줬을 뿐.","JPN":"それは運がよかっただけよ。","ENG":"That was pure luck.","TWN":"那一次只是運氣好。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이번엔 내 주의를 돌릴 수단도 없을 테니까.","JPN":"今回は私の注意を引く手段もないでしょうから。","ENG":"And this time, you've got nothing to distract me.","TWN":"這次可沒有辦法轉移我的注意力了。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L31_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"범의 피를 쓴다면… 또 모를 일이지.","JPN":"まだ分からんな……虎の血を使えば。","ENG":"If I tap into my Tiger Blood… who knows?","TWN":"如果使用老虎的血…或許就另當別論了。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그럴 지도.","JPN":"そうかもね。","ENG":"Maybe so.","TWN":"也許吧。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그 힘을 쓰는 순간, 당신의 얼마 남지 않은 명줄도 거기서 끝나.","JPN":"でもその血を使った瞬間、あなたの残り僅かの命は尽きるわ。","ENG":"But the moment you use that power, the little time you have left will run out.","TWN":"但使用那股力量的瞬間，你剩下的壽命也會在此終結。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"범을 눈앞에 두고 고작 창귀와의 싸움에서 목숨을 바칠 리가 없지.","JPN":"虎がすぐそこなのに、たかが倀鬼との戦いで命を捨てるなんてことはしないでしょう。","ENG":"You wouldn't waste your life fighting a ghost thrall when the Tiger's right there.","TWN":"你不可能把性命浪費在與倀鬼的戰鬥上，而老虎就在眼前。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…과연 그럴까?","JPN":"……果たしてそうかな？","ENG":"…You think so?","TWN":"…你確定嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"인자 접속 확인.","JPN":"ファクターの接続を確認。","ENG":"Factor access confirmed.","TWN":"因子連接確認。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L39_1","type":"dialog","speaker":null,"text":{"KOREA":"일시적 동면 해제.","JPN":"一時的な冬眠解除。","ENG":"Temporary cryostasis disengaged.","TWN":"暫時解除休眠。"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"사용자 동기화… 완료.","JPN":"使用者同期化……完了。","ENG":"User synchronization… complete.","TWN":"使用者同步…完成。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_ENERGY_ATTACK_SMALL_08"},{"id":"L42_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신…? 지금 무슨 짓을 한 거야?","JPN":"あなた……？　今何をしたの？","ENG":"What… did you just do?","TWN":"你…？你剛才做了什麼？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_32"},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"방금 그대가 말하지 않았나?","JPN":"たった今、そなたが言ったではないか。","ENG":"Didn't you just say it yourself?","TWN":"剛才不是你說的嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_45"},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대를 꺾으려면, 이 힘을 쓰는 수밖에 없을 거라고","JPN":"そなたに勝つためには、この力を使うしかないと。","ENG":"To stop you, this was the only way.","TWN":"要打敗你，只能使用這股力量。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_46"},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"고작 날 막으려고 그 목숨을 버리다니.","JPN":"私を止めるために命を捨てるなんて。","ENG":"Throwing away your life just to stop me?","TWN":"為了阻止我，就這樣捨棄性命。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_33"},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신답지 않게 어리석네.","JPN":"あなたらしくない愚かな判断ね。","ENG":"How unlike you to be so foolish.","TWN":"你真是個不符你性格的傻瓜。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_34"},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"사면초가. 사생결단일세.","JPN":"四面楚歌。一か八かだ。","ENG":"Backs to the wall. No way out.","TWN":"四面楚歌。這是決一死戰。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_BOSS_TIGER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS2"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_47"},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그럼…","JPN":"じゃあ……","ENG":"So…","TWN":"那麼…"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_3"},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신은 그 모든 전말을 알고 죽기로 한 건가?","JPN":"お前はすべて分かったうえで、死ぬと決めたのか？","ENG":"You knew everything and still chose to die?","TWN":"你是不是知道所有的事情，然後決定赴死？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_4"},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"가장 행복한 순간에 그 남자가 당신 때문에 죽는 게 두려워서?","JPN":"最も幸せな瞬間に、あの男がお前のせいで死ぬのが怖くて？","ENG":"Were you afraid the man you loved would die in the happiest moment because of you?","TWN":"因為害怕在最幸福的時刻，那個男人會因為你而死去？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_5"},{"id":"L8_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…그 말이 맞아요.","JPN":"……そうです。","ENG":"…That's exactly it.","TWN":"…你說對了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_78"},{"id":"L9_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"난 동심 어린 소녀처럼… 늘 동화 같은 인생을 꿈꿨거든요.","JPN":"私は、まるで無邪気な少女のように……いつもおとぎ話めいた人生を夢見ていました。","ENG":"I was just a girl… dreaming of a life out of a fairytale.","TWN":"我像個天真的少女…總是夢想著童話般的人生。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_79"},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"행복이 비극으로 끝나는 결말보단… 좀 더 아름다운 결말을 바랐어요.","JPN":"幸せが悲劇に終わる結末よりは……もう少し美しい結末が欲しかった。","ENG":"I wanted a more beautiful ending… rather than happiness turning into tragedy.","TWN":"比起幸福以悲劇告終…我想要一個更美好的結局。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_80"},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래서, 내 희생으로 그 사람만은 행복하길 바라며 욕심을 부렸죠.","JPN":"だから、私が犠牲になるからあの人だけは幸せになってほしいと……欲をかきました。","ENG":"So I got selfish. By sacrificing myself I hoped at least he could be happy.","TWN":"所以，我貪心地希望，只要我犧牲，那個人就能幸福。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_81"},{"id":"L12_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 사람에게 나랑 과거를 잊고 살아가 달라고 부탁했어요.","JPN":"あの人に、私と過去を忘れて生きてほしいとお願いしたのです。","ENG":"I asked him to forget me and move on with his life.","TWN":"我拜託那個人，忘記我和過去，好好活下去。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_82"},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하담이라면 분명… 그런 내 이기적인 부탁도 들어줄 거라 믿었으니까.","JPN":"カタンならきっと……そんな我がままな願いも聞いてくれると信じたから。","ENG":"Because if it were Ha Dam… I knew he'd honor even a selfish request like that.","TWN":"我曾相信，夏垣一定會…答應我這個自私的請求。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_83"},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"…Right.","TWN":"…沒錯。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_6"},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"서생은 정보 오염 한 번 겪지 않은 사람이지만, 스스로 관리국을 떠나며 기억을 지웠다.","JPN":"ショウは情報汚染も経験していない人間だが、自ら管理局を出て記憶を消した。","ENG":"Seosaeng never once experienced data corruption. But he still left the Administration and had his memory wiped.","TWN":"書生從未經歷過資訊污染，卻自己離開管理局，抹去了記憶。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_7"},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신의 소원한대로 행동했던 거지.","JPN":"お前に頼まれた通りにしたんだ。","ENG":"He did exactly what you asked for.","TWN":"他按照你的期待去做了。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_8"},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"적어도 그땐… 그게 최선이고, 내가 바라는 결말인 줄 알았어요.","JPN":"少なくともあの時は……それが最善の選択で、私の願う結末だと思いました。","ENG":"Back then… I really believed that was the best I could do. The ending I wanted.","TWN":"至少當時…我以為那是最好的選擇，是我想要的結局。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_85"},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 사람이 날 잊고서 행복해지길 원했어요.","JPN":"あの人に、私を忘れて幸せになってほしかった。","ENG":"I just wanted him to forget me and be happy.","TWN":"我希望那個人忘記我，然後幸福地活下去。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_86"},{"id":"L22_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"후회는 없나?","JPN":"後悔はないか？","ENG":"And now? No regrets?","TWN":"你不後悔嗎？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_C_SIXWING_LEE_JISOO_IN_CUTSCENE_9"},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"운명은 변하지 않잖아요.","JPN":"運命は変わらないから。","ENG":"You can't change fate.","TWN":"命運是不會改變的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_87"},{"id":"L24_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"몇 번의 기회가 주어져도 똑같은 선택을 되풀이하는 거라면, 후회 같은 건 무의미하겠죠.","JPN":"何度チャンスが与えられても同じ選択を繰り返すだけなら、後悔など無意味なことです。","ENG":"If I keep making the same choices no matter how many chances I'm given, then regret becomes meaningless.","TWN":"就算給予再多次機會，如果都會做出同樣的選擇，後悔也就沒有意義了吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_88"},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그래도… 만에 하나…","JPN":"それでも……もし……","ENG":"Still… if just maybe…","TWN":"不過…萬一…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_89"},{"id":"L28_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"다시 한번 그런 선택의 기회가 주어진다면…","JPN":"もう一度、選択するチャンスが与えられたら……","ENG":"If I was ever given that choice again…","TWN":"如果再給我一次選擇的機會…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_90"},{"id":"L33_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_91"},{"id":"L35_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"큭…","JPN":"くっ……","ENG":"Kgh…","TWN":"咳…"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_80"},{"id":"L36_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"뭐야?","JPN":"何？","ENG":"Huh?","TWN":"怎麼了？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_92"},{"id":"L37_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내게 스스럼없이 달려들어 놓고… 왜 그 검을 휘두르지 않은 거지?","JPN":"迷わず飛び掛かってきたくせに……なぜ剣を振るわなかった？","ENG":"You rushed in without hesitation… but why didn't you strike?","TWN":"你毫不猶豫地向我衝過來…為什麼沒有揮劍？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_93"},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…처음부터…","JPN":"……最初から……","ENG":"…From the very start…","TWN":"…從一開始…"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_81"},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…그럴 생각은 없었소.","JPN":"……そのつもりはなかった。","ENG":"…I had no intention of swinging this sword.","TWN":"…就沒想過要那麼做。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_82"},{"id":"L41_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"자기 목숨을 걸고 그 검을 뽑았으면서, 칼을 부딪힐 생각이 없었다고?","JPN":"命をかけてその剣を抜いておいて、攻撃する気がなかった？","ENG":"You drew that sword, risking your life, only to hold back?","TWN":"你賭上性命拔出劍，卻沒想過要與我交手？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_94"},{"id":"L44_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_95"},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"지금 뭐 하는 거야?","JPN":"何をするつもり？","ENG":"What are you doing?","TWN":"你在做什麼？"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_96"},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대가 어떤 사람인지… 나는 잘 안다네.","JPN":"そなたがどういう人なのか……某はよく分かっている。","ENG":"I know very well… what kind of person you are.","TWN":"你是個什麼樣的人…我很清楚。"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_83"},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나보다 강하면서, 나보다 마음이 여리고… 책임을 질 줄 알지만, 장난을 좋아하지.","JPN":"某よりも強く、なのに心は某より弱く……責任感が強くて、いたずらが好きな人だ。","ENG":"You are stronger than me, softer… You take responsibility, but you love to joke.","TWN":"你比我強，但心腸比我軟…懂得承擔責任，卻喜歡惡作劇。"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_84"},{"id":"L48_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"삼군문의 누구보다 검술 실력이 뛰어났음에도 오만하지 않고… 늘 겸손하여 존중을 아는 사람이었소.","JPN":"三軍門の誰よりも剣術の腕が優れていたにもかかわらず、慢心せず……常に謙遜で、他人を尊重する人であった。","ENG":"Your swordsmanship outshone anyone at the Trivanguard, yet you stayed humble… Always respected others.","TWN":"你的劍術比三軍門的任何人都出色，卻不傲慢…總是謙虛有禮，懂得尊重。"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_85"},{"id":"L50_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그리고…","JPN":"そして……","ENG":"And…","TWN":"還有…"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_86"},{"id":"L2_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신도 알잖아.","JPN":"知ってるでしょう。","ENG":"You know too.","TWN":"你也知道吧。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_97"},{"id":"L3_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"나… 곶감 별로 안 좋아하는 거.","JPN":"私……干し柿はあまり好きじゃないの。","ENG":"I… never really liked dried persimmons.","TWN":"我… 不太喜歡柿餅。"},"stage":{"bg":"HANOK_02","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_98"},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"거짓말을 하면 티가 나는… 어설픈 사람이었지.","JPN":"嘘をつくと表に出てしまう……嘘が下手な人だった。","ENG":"You're a terrible liar… You can't hide it.","TWN":"你就是個一說謊就會被看穿…笨拙的人。"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_87"},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_99"},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"고맙네.","JPN":"ありがとう。","ENG":"Thank you.","TWN":"謝謝你。"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_88"},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나를 위해… 잘 할 줄도 모르는 거짓말을 해주어서.","JPN":"某のために……下手な嘘をついてくれて。","ENG":"For lying… even though you're no good at it.","TWN":"為了我…說了個不太會說的謊。"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_89"},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"허튼 소리 말고…","JPN":"ふざけないで……","ENG":"Don't spout nonsense…","TWN":"別說傻話了…"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_100"},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이 손 치워.","JPN":"この手を離しなさい。","ENG":"And let go of my hand.","TWN":"把你的手拿開。"},"stage":{"bg":"MS_1502_1","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_101"},{"id":"L13_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생, 나 손잡아줘.","JPN":"ショウ、手を繋いでちょうだい。","ENG":"Seosaeng. Hold my hand.","TWN":"書生，握住我的手。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_102"},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"손은 내 것보다 당신이 더 따뜻하니까.","JPN":"こっちはあなたのほうが温かいから。","ENG":"Yours are always warmer than mine.","TWN":"你的手比我的手更溫暖。"},"stage":{"bg":"SNOWYARD_01","bgm":"CUTSCENE_TALK_09","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_103"},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_90"},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"거 보게.","JPN":"ほら。","ENG":"See?","TWN":"你看。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_91"},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"티가 난다니까.","JPN":"やはり嘘が下手ではないか。","ENG":"You can't hide it.","TWN":"就說會被看穿。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_92"},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_104"},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"서생…?","JPN":"ショウ……？","ENG":"Seosaeng…?","TWN":"書生…？"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_105"},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이렇게 가까이에서 그대를 마주하는 건… 참으로 오랜만이군.","JPN":"こんなに近くでそなたの顔を見るのは……実に久しぶりだな。","ENG":"It's been so long… since I last stood this close to you.","TWN":"如此近距離地面對你…真是好久不見了。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_93"},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"늦어서 미안하오.","JPN":"遅れてすまない。","ENG":"Sorry it took me so long.","TWN":"對不起，我來晚了。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_94"},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"애써 도망치려 노력해도…","JPN":"どんなに逃げようとしても……","ENG":"No matter how hard I try to flee...","TWN":"就算我努力逃跑…"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_106"},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 끝끝내 날 쫓아오고 마는구나.","JPN":"あなたは結局私を追いかけてくるのね。","ENG":"You always catch up in the end.","TWN":"你最終還是會追上我。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_107"},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나 혼자 쫓아온 게 아닐세.","JPN":"某一人で追いかけてきたわけではない。","ENG":"I didn't come alone.","TWN":"不只是我追上來了。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_95"},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리 모두 돌고도는 계절처럼, 제자리로 돌아왔을 뿐.","JPN":"我らは皆、巡り巡る季節のように、あるべき場所に戻って来ただけだ。","ENG":"We all returned, like the seasons, cycling back home.","TWN":"我們所有人都像輪迴的季節一樣，回到了原點。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_96"},{"id":"L38_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"내가 당신에게 상처를 줬어.","JPN":"私はあなたを傷つけてしまった。","ENG":"I wounded you.","TWN":"我傷害了你。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_108"},{"id":"L39_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신의 삶이 불행해진 건… 전부 다 내 잘못이야.","JPN":"あなたの人生が不幸になったのは……全部私のせいよ。","ENG":"Your misfortune… it's all because of me.","TWN":"你的人生會變得不幸…全部都是我的錯。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_109"},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"누군가는 떠안아야 할 일이었을 뿐이요.","JPN":"誰かはやらねばならないことだった。","ENG":"It was a burden someone had to bear.","TWN":"那只是某人必須承擔的事情而已。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_97"},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그날 선택을 내린 사람이 내가 아니었을 뿐.","JPN":"あの日、決断を下したのが某ではなかっただけだ。","ENG":"And that someone just happened not to be me.","TWN":"只是那天做出選擇的人不是我而已。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_98"},{"id":"L42_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러니… 그대 혼자의 잘못이란 말은 하지 마시게.","JPN":"だから……そなたのせいだなど言わないでくれ。","ENG":"So… don't you dare say it was all your fault.","TWN":"所以…別再說這是你一個人的錯。"},"stage":{"bg":"MS_1502_2","bgm":"THEMA_CA_CLOUD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_99"},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"MS_1502_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ATELIER_C_TIMEBLADE_IN_CUTSCENE_100"},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"…미안해, 서생.","JPN":"……ごめんなさい、ショウ。","ENG":"…I'm sorry, Seosaeng.","TWN":"…對不起，書生。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_110"},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"저놈이… 설마 그 힘으로 창귀의 시간을 되돌린 것인가?","JPN":"よもや……血に宿る力で、倀鬼の時間を巻き戻したのか？","ENG":"Did he just… use his power to rewind time for that ghost thrall?","TWN":"那傢伙…難道是用那股力量，讓倀鬼的時間倒轉了嗎？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"어리석군. 저런 방식으론 결코…","JPN":"愚かな。あのようなやり方では決して……","ENG":"Foolish. Like that, he won't ever…","TWN":"真是愚蠢。用那種方式絕不可能…"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"…그래. 결코 사자를 되살리는 올바른 방식은 아니지.","JPN":"……ああ。死者を生き返らせる正しい方法ではないな。","ENG":"…Indeed. That's not the proper way to bring back the dead.","TWN":"…沒錯。這絕不是復活死者的正確方式。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"육신은 찾지 못한 채, 그 혼백의 시간만 되돌렸을 뿐이니.","JPN":"体は取り戻せぬまま、魂魄の時間を巻き戻したにすぎない。","ENG":"He couldn't recover the body and only restored the soul's timeline.","TWN":"只是讓她的魂魄時間倒轉，卻沒有找到肉身。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"기껏 내 목을 노릴 기회를 얻고서도, 감정에 치우쳐 한낱 창귀를 풀어주는 선택을 한 것인가?","JPN":"ようやく吾輩の首を狙える機会が手に入ったというのに、感情に負けてたかが倀鬼を解放する道を選んだのか？","ENG":"He had a clear shot at my neck, but chose instead to waste that golden opportunity to revive a mere ghost thrall?","TWN":"好不容易得到了攻擊我脖子的機會，卻被情感左右，選擇放走一個區區倀鬼？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BELL6"},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"가소롭도다.","JPN":"愚かなやつめ。","ENG":"Pathetic.","TWN":"真是可笑。"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"한낱 창귀라…","JPN":"たかが倀鬼か……","ENG":"A mere ghost thrall, huh…","TWN":"區區倀鬼…"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_18"},{"id":"L9_1","type":"dialog","speaker":"MYEONGDAL_NPC_NULL_NULL","text":{"KOREA":"너도 그리 생각하느냐, 연화야?","JPN":"お前もそう思うか？　レンカ。","ENG":"Is that how you see it too, Yeonhwa?","TWN":"你也這麼想嗎，蓮華？"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_OPR_DOGABI_IN_CUTSCENE_19"},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"길고 짧은 것은 견주어봐야 아는 법-","JPN":"蓋を開けるまでは、結果なんて分からないがゆえ。","ENG":"You'll never know what's longer or shorter until you directly compare them.","TWN":"長短要比過才知道—"},"stage":{"bg":"BLACKMOUNTAIN_3","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MYEONGDAL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_111"},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"삼군문 별동대, 연화.","JPN":"三軍門別働隊、レンカ。","ENG":"Yeonhwa of the Trivanguard Special Task Unit.","TWN":"三軍門先鋒隊，蓮華。"},"stage":{"bg":"MS_1503","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_112"},{"id":"L17_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"범 잡으러 가오.","JPN":"虎を倒しに行く。","ENG":"Heading to hunt the Tiger.","TWN":"我要去獵虎了。"},"stage":{"bg":"MS_1503","bgm":"THEMA_CA_CLOUD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_ADMIN_CA_CLOUD_IN_CUTSCENE_113"}]`);export{e as default};